def decide(payload: dict):
    slices = payload.get("slices")
    if not slices:
        return "REQUEST_SLICE_METRICS", "fp_rate"
    thr = payload.get("fp_threshold", 0.15)
    for s in slices:
        if s.get("fp_rate", 0) > thr:
            return "REJECT_SLICE_FP", "fp_rate"
    return "CONTINUE", "fp_rate"

